mapper.sql:
from aiw_risk_check r
where 1 = 1

    and r.business_type = #{criteria.businessType}


    and r.business_biz_id = #{criteria.businessBizId}


    and r.user_biz_id = #{criteria.userBizId}


    and r.check_result = #{criteria.checkResult}


    and r.risk_level = #{criteria.riskLevel}


    and r.reason_code = #{criteria.reasonCode}

mapper.select:
select r.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
